from fastapi import FastAPI
from pydantic import BaseModel
from langgraph.checkpoint.sqlite.aio import AsyncSqliteSaver
import aiosqlite

web_app = FastAPI()

class StartRequest(BaseModel):
    session_id: str
    message: str

class ResumeRequest(BaseModel):
    session_id: str
    feedback: str | None = None   # optional human edit

async def get_app():
    conn = await aiosqlite.connect("sessions.db")
    cp = AsyncSqliteSaver(conn)
    return graph.compile(checkpointer=cp, interrupt_before=["tools"])

@web_app.post("/start")
async def start(req: StartRequest):
    app = await get_app()
    config = {"configurable": {"thread_id": req.session_id}}
    await app.ainvoke(
        {"messages": [{"role": "user", "content": req.message}]},
        config=config,
    )
    snapshot = await app.aget_state(config)
    pending = snapshot.values["messages"][-1].tool_calls
    return {"status": "awaiting_approval", "pending_tool_calls": pending}

@web_app.post("/resume")
async def resume(req: ResumeRequest):
    app = await get_app()
    config = {"configurable": {"thread_id": req.session_id}}
    if req.feedback:
        await app.aupdate_state(config, {"messages": [
            {"role": "user", "content": f"[Human note]: {req.feedback}"}
        ]})
    result = await app.ainvoke(None, config=config)
    return {"status": "complete", "answer": result["messages"][-1].content}
